import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { Task } from '../../models/task.model';
import { TaskFormComponent } from '../task-form/task-form.component';
import { TaskService } from '../../services/task.service'; 

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [CommonModule, FormsModule, TaskFormComponent],
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.css']
})
export class TaskListComponent implements OnInit {
  tasks: Task[] = [];
  users: any[] = []; 
  taskToEdit: Task | null = null;
  isModalOpen: boolean = false;

  // 👇 Controla qué pantalla se está viendo
  currentView: 'board' | 'reports' = 'board';

  filterAssignee: string = '';
  filterStartDate: string = '';
  filterEndDate: string = '';

  private taskService = inject(TaskService);
  private router = inject(Router);

  ngOnInit() {
    this.loadTasks();
    this.loadUsers();
  }

  loadTasks() {
    this.taskService.getTasks().subscribe({
      next: (data) => { this.tasks = data; },
      error: (err) => console.error('Error al cargar tareas', err)
    });
  }

  loadUsers() {
    this.taskService.getUsers().subscribe({
      next: (data) => { this.users = data; },
      error: (err) => console.error('Error al cargar usuarios', err)
    });
  }

  logout() {
    localStorage.removeItem('token');
    localStorage.removeItem('currentUser');
    this.router.navigate(['/login']);
  }

  switchView(view: 'board' | 'reports') {
    this.currentView = view;
  }

  get userStats() {
    return this.users.map(user => {
      const userTasks = this.tasks.filter(t => t.assignee === user.name);
      const completed = userTasks.filter(t => t.status === 'completed').length;
      const total = userTasks.length;
      const percentage = total === 0 ? 0 : Math.round((completed / total) * 100);

      return { 
        name: user.name, 
        completed, 
        total, 
        percentage 
      };
    }).sort((a, b) => b.completed - a.completed);
  }

  getTasksByStatus(status: 'pending' | 'in-progress' | 'completed' | 'on-review' | 'blocked'): Task[] {
    return this.tasks.filter(task => {
      if (task.status !== status) return false;
      if (this.filterAssignee && task.assignee !== this.filterAssignee) return false;
      if (this.filterStartDate && (!task.startDate || task.startDate < this.filterStartDate)) return false;
      if (this.filterEndDate && (!task.endDate || task.endDate > this.filterEndDate)) return false;
      return true;
    });
  }

  clearFilters() {
    this.filterAssignee = '';
    this.filterStartDate = '';
    this.filterEndDate = '';
  }

  changeStatus(task: Task, newStatus: 'pending' | 'in-progress' | 'completed' | 'on-review' | 'blocked') {
    if (!task.id) return;
    const oldStatus = task.status;
    task.status = newStatus;
    this.taskService.updateTask(task.id, { status: newStatus }).subscribe({
      error: (err) => { console.error('Error', err); task.status = oldStatus; }
    });
  }

  deleteTask(id: string | undefined) {
    if (!id) return;
    this.taskService.deleteTask(id).subscribe({
      next: () => { this.tasks = this.tasks.filter(task => task.id !== id); },
      error: (err) => console.error('Error al eliminar', err)
    });
  }

  openNewTaskModal() { this.taskToEdit = null; this.isModalOpen = true; }
  editTask(task: Task) { this.taskToEdit = { ...task }; this.isModalOpen = true; }
  closeModal() { this.isModalOpen = false; this.taskToEdit = null; }

  onTaskAdded(newTask: Task) {
    this.taskService.createTask(newTask).subscribe({
      next: (createdTask) => { this.tasks.unshift(createdTask); this.closeModal(); },
      error: (err) => console.error('Error al crear', err)
    });
  }

  onTaskUpdated(updatedTask: Task) {
    if (!updatedTask.id) return;
    this.taskService.updateTask(updatedTask.id, updatedTask).subscribe({
      next: (savedTask) => {
        const index = this.tasks.findIndex(t => t.id === savedTask.id);
        if (index !== -1) { this.tasks[index] = savedTask; }
        this.closeModal(); 
      },
      error: (err) => console.error('Error al actualizar', err)
    });
  }
}
